INSERT INTO `blogs` (`id`, `title`, `description`, `content`, `image`, `service_category_id`, `slug`, `created_at`, `updated_at`) VALUES
(17, 'เขื่อนกันดินไทรม้า 19 EP.1', 'สร้างเขื่อนกันดินซอยไทรม้า 19 ระยะความยาวทั้งหมด 49.5 เมตร', '<p><strong>งานกำแพงกันดิน ซอยไทรม้า 19 EP.1</strong></p>\n\n<p>วันแรกของการเริ่มงานสร้างเขื่อนกันดิน ซอยไทรม้า 19 เพื่อเป็นขวัญและกำลังใจในการทำงานของทีมงาน จึงมีการเซ่นไหว้ เจ้าที่ เจ้าทาง เพือขอขมา และขอพรสิ่งศักดิ์สิทธิ์ที่อยู่บริเวณโดยรอบ ให้สามารถดำเนินการไปได้ด้วยความเรียบร้อย และปลอดภัย</p>\n\n<p><img alt=\"\" src=\"{{asset(\'images/blogs/blogcontent/saima-19-1.webp\')}}\" style=\"height:400px; width:300px\" /></p>\n\n<p>รายละเอียดงานนี้ เป็นงานทำกำแพงเขื่อนกันดินความยาวทั้งหมด 49.5 เมตร พร้อมสเตย์เพื่อเพิ่มความแข็งแรงให้เขื่อนกันดิน สามารถรับแรงอัดจากด้านข้างได้เป็นอย่างดี และมีประสิทธิภาพ โดยจะใช้เป็นเข็ม(Micropile) I22 ความยาง 10 เมตร พร้อมสเตย์ทุกต้น</p>\n\n<p><img alt=\"วันแรกงานสร้างเขื่อนกันดิน\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/28165.webp\" style=\"height:225px; width:300px\" /></p>\n\n<p>&nbsp;</p>\n\n<p><img alt=\"\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/saima-19-bobby.webp\" style=\"height:225px; width:300px\" /></p>\n\n<div class=\"ml-4\"><p>เข็ม Micropile I22 ทั้งหมดทีใช้ในงานนี้ 110 ต้น</p>\n\n<p>อุปสรรค และปัญหาที่เจอ</p>\n\n<ol>\n	<li><a href=\"https://www.theeraphong.com/รับถมดิน\">ดิน ถม</a> เดิม เป็นดินเลน ทำให้ดินไม่แน่ หรือว่ามีความแข็งแรงค่อนข้างน้อย</li>\n	<li>แนวสันเขื่อนเดิม มีหินอยู่ด้านล่าง ทำให้ยากต่อการตอกเสาเข็ม</li>\n</ol>\n\n<p>&nbsp;</p>\n\n<hr />\n<p>ส่วนวิธีการแก้ไขปัญหา จะมีการนำเสนอในตอนต่อไป</p></div>\n\n\n\n<p>&nbsp;</p>\n\n<p>&nbsp;</p>', 'images/blogs/1710671722259177.webp', 10, 'เขื่อนกันดิน-ไทรม้า19-EP1', '2021-09-12 05:14:45', '2021-09-12 09:10:06'),
(18, 'เขื่อนกันดินไทรม้า 19 EP.2', 'อัพเดทงานสร้างเขื่อนกันดิน ซอยไทรม้า 19', '<h1><strong>อัพเดทงานสร้างเขื่อนกำแพงกันดิน&nbsp;</strong></h1>\r\n\r\n<p>อัพเดทวันที่ 14-09-2021</p>\r\n\r\n<p>ทางทีมงานได้เริ่มดำเนินการขนย้ายเข็มเข้าพื้นที่ เพื่อเตรียมกดเสาเข็มไอ ด้วยแมคโคร</p>\r\n\r\n<p>แต่ยังคงพบปัญหาเรื่องหินที่อยู่ด้านล่างใต้น้ำ ซึ่งต้องมีการดำเนินการนำหินออก ก่อนการกดเสาเข็ม(Micropile) ความยาว 10 เมตร</p>\r\n\r\n<p>เสาเข็มทั้งหมด 110 ต้น คาดการณ์ว่า น่าจะใช้เวลาประมาณ 4-5 วัน โดยประมาณ</p>\r\n\r\n<p><img alt=\"เสาเข็มไอ(Micropile)\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/15092021/saima-19-15092021-2.webp\" style=\"height:375px; width:500px\" /></p>\r\n\r\n<p>พร้อมทั้งทีมงานได้เตรียมพื้นที่ และอุปกรณ์สำหรับหล่อแผ่นเสียบ ด้วยโครงเหล็กคุณภาพดี และมีมาตรฐานหน้างาน</p>\r\n\r\n<p>เพื่อใช้เสียบแผ่น หลังจากที่ลงเสาเข็มเสร็จ</p>\r\n\r\n<p><img alt=\"พิมพ์หล่อแผ่นเสียบ\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/15092021/saima-19-15092021-3.webp\" style=\"height:375px; width:500px\" /></p>\r\n\r\n<p>&nbsp;</p>', 'images/blogs/1710950087706025.webp', 10, 'เขื่อนกันดิน-ไทรม้า19-EP2', '2021-09-15 06:59:15', '2021-09-15 06:59:15'),
(19, 'เขื่อนกันดินไทรม้า 19 EP.3', 'แก้ไขปัญหาหินใต้น้ำ งานสร้างเขื่อนกันดิน ซอยไทรม้า 19', '<h1><strong>ปัญหาหน้างาน Retaining wall</strong></h1>\r\n\r\n<p>วันนี้ทางทีมงานได้เริ่มกดเสาเข็ม ด้วยแมคโคร และเจอปัญหาหลักคือ หินที่อยู่ใต้น้ำ ซึ่งสันเขื่อนเดิมได้ทิ้งหินไว้</p>\r\n\r\n<p>จึงต้องมีการนำแมคโคร เข้ามาเกลี่ยหินที่อยู่ใต้น้ำก่อน จึงจะสามารถ<a href=\"https://www.theeraphong.com/images/pile\" target=\"_blank\">กดเข็ม</a>ลงได้ ซึ่งทำให้งานเกิดความล่าช้าไปบ้าง</p>\r\n\r\n<p>แต่ก็ไม่เกินความคาดหมายที่ได้วางแผนไว้</p>\r\n\r\n<p><img alt=\"หินใต้น้ำ\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/15092021/saima-19-15092021-7.webp\" style=\"height:375px; width:500px\" /></p>\r\n\r\n<p>รูป หินใต้น้ำ</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>วันนี้ถึงแม้จะมีหินเป็นอุปสรรค แต่ด้วยทีมงานที่มีความเชียวชาญ งานกดเสาเข็มก็สามารถเป็นไปตามแผนที่คาดคิดไว้ ถึงแม้จะล่าช้าบ้างเล็กน้อย ก็ไม่มีผลอะไรมากนัก</p>\r\n\r\n<p><img alt=\"แม็คโคร โก เบ 135 กดเข็ม\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/15092021/saima-19-15092021-8.webp\" style=\"height:375px; width:500px\" /></p>\r\n\r\n<p><strong>&nbsp;</strong>รูป กดเข็ม Micropile ด้วยแบ็คโฮ</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>และสำหรับงานแผ่นเสียบ ได้ดำเนินการเทปูนเป็นที่เรียบร้อยระยะเวลาในช่วงที่กดเข็ม และรอแผ่นปูนเซ็ตตัว ก็จะพอดีกัน</p>\r\n\r\n<p>หลังจากกดเสาเข็มเสร็จเรียบร้อย ก็จะสามารถนำแผ่นเสียบกำแพงกันดินไปเสียบได้ทันที</p>\r\n\r\n<p><img alt=\"เทปูนแผ่นเสียบกำแพงกันดิน\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/15092021/saima-19-15092021-6.webp\" style=\"height:500px; width:375px\" /></p>\r\n\r\n<p>รูป งานเทปูนแผ่นเสียบกำแพงกันดิน 1</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/15092021/saima-19-15092021-10.webp\" style=\"height:375px; width:500px\" /></p>\r\n<p>รูป งานเทปูนแผ่นเสียบกำแพงกันดิน 2</p>\r\n\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/wSa5U9nbfDI\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture\" allowfullscreen></iframe>\r\n<p>วิดีโอ แมคโครขุดหินที่อยู่ใต้น้ำ</p>', 'images/blogs/1710962864135948.webp', 10, 'เขื่อนกันดิน-ไทรม้า19-EP3', '2021-09-15 10:22:19', '2021-09-15 10:30:48'),
(20, 'เขื่อนกันดินไทรม้า 19 EP.4', 'อัพเดทงานสร้างเขื่อนกันดิน ซอยไทรม้า 19', '<h1><strong>อัพเดทงาน กำแพงกันดิน ซอย ไทรม้า 19</strong></h1>\r\n\r\n<p>หน้างาน ทำกำแพงกันดิน ยังคงเนินการไปได้เรื่อย ๆ แต่ก็ประสบกับปัญหาหลัก ที่ทำให้ล่าช้า คือ หินที่อยู่ใต้น้ำที่มีค่อนข้างมาก รถแบคโฮ จึงต้องทำงานสองอย่าง คือ</p>\r\n\r\n<ol>\r\n	<li>เคลียหิน</li>\r\n	<li>กดเข็ม</li>\r\n</ol>\r\n\r\n<p>&nbsp;</p>\r\n<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/vmWXNdmQ6qM\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture\" allowfullscreen></iframe>\r\n<p>&nbsp;</p>\r\n\r\n<p>ทั้งนี้ทางทีมงานก็เร่งดำเนินการให้งานจบออกมา แล้วสามารถเสร็จทันตามกำหนดเวลา โดยยังคงไว้ซึ่งมาตรฐานที่เคยทำมาเป็นที่ตั้งสูงสุด</p>\r\n\r\n<p>โดยความคืบหน้าสามารถดำเนินการไปได้ มากกว่า 30% ของงานทั้งหมด&nbsp;</p>\r\n\r\n<blockquote>\r\n<p><strong>&quot;งานยากไม่ว่า เสียหน้า ธีรพงษ์ ไม่ยอม&quot;</strong></p>\r\n</blockquote>\r\n\r\n<p>รวมถึงแผ่นเสียบที่ใช้หล่อสดหน้างาน ซึ่งจะใช้เสียบเข้าระหว่างเสาเข็มเมื่อการกดเข็ม ไอ 22 ด้วยแบคโฮ แล้วเสร็จ สามารถดำเนินการไปได้มากกว่า 25%&nbsp;</p>\r\n\r\n<p><img alt=\"\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/17092021/saima-19-rw-170921-1.webp\" style=\"height:500px; width:375px\" /></p>', 'images/blogs/1711139361714176.webp', 10, 'เขื่อนกันดิน-ไทรม้า19-EP4', '2021-09-17 09:07:41', '2021-09-17 09:07:41'),
(21, 'กำแพง กัน ดิน ซอยบางกร่าง45/5 EP.1', 'เริ่มงานทำกำแพงกันดิน ซอยบางกร่าง 45/5', '<p>วันนี้วันแรกสำหรับงานกำแพง กัน ดิน ซอยบางกร่าง 45/5 ติดริมคลองบางนางเกริก และคลองอ้อมน้อย</p>\r\n\r\n<p><img alt=\"คลองนางบางเกริก\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/190921/bangkrang45-1.webp\" style=\"height:375px; width:500px\" /></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>ก่อนอื่นเลย ต้องขอขอบพระคุณ คุณ คุณพี่มนัส ที่ไว้วางใจให้ทีมงาน ธีรพงษ์ เซอร์วิส ให้ดำเนินการทำ&nbsp;<a href=\"https://www.theeraphong.com/retaining-wall\">กำแพง กัน ดิน</a>&nbsp;ให้</p>\r\n\r\n<p>ก่อนเริ่มงาน ต้องบอกก่อนว่าเดิมที ทางคุณพี่มนัส ของเรามีกำแพง กัน ดิน เดิมอยู่แล้ว แต่เนืองจากแบบ กำแพง กัน ดิน เดิม ได้เกิดความเสียหาย ล้ม หรือพังลงไปทางฝั่งแม่น้ำ เพราะสเตย์ที่ยึดกำแพงกันดิน มีขนาดเล็กเกินไป ทำให้ไม่มีความแข็งแรงเพียงพอ จึงทำให้ไม่สามารถยึดกำแพงกันดินเอาไว้ได้&nbsp;</p>\r\n\r\n<p><img alt=\"กำแพงกันดินพัง\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/190921/bangkrang45-2.webp\" /></p>\r\n\r\n<p>รูป กำแพงกันดินที่เสียหาย</p>\r\n\r\n<p>ทีมงานเราจึงได้รับความไว้วางใจจากคุณพี่มนัส ให้เข้ามาดำเนินการทำ กำแพง กัน ดิน สเตย์ ให้ใหม่</p>\r\n\r\n<p>รายละเอียดขั้นตอนการดำเนินการ ทางทีมงาน ธีรพงษ์ จะนำเสนอรายละเอียดในรายการถัดไป มาคอยดูกันว่าทางทีมงานเราจะมีวิธีจัดการแบบใด</p>\r\n\r\n<p>&nbsp;</p>\r\n<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/bXvRyK0OZj4\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture\" allowfullscreen></iframe>\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>รวมรูปภาพผลงาน <a href=\"https://www.theeraphong.com/images/retaining-wall\">คลิ๊กได้เลย</a></p>\r\n\r\n<p>บทความ และข่าวสารล่าสุด <a href=\"https://www.theeraphong.com/blog\">คลิ๊กได้เลย</a></p>', 'images/blogs/1711320597112563.webp', 10, 'กำแพงกันดิน-ซอยบางกร่าง45-5-EP1', '2021-09-19 08:43:10', '2021-09-20 00:35:42'),
(22, 'เขื่อนกันดินไทรม้า 19 EP.5', 'อัพเดทงานสร้างเขือนกันดิน ซอยไทรม้า 19 ณ 20 ก.ย. 2564', '<p><strong>อัพเดทงาน ณ วันที่ 20 กันยายน 2564</strong></p>\r\n\r\n<p>วันนี้ ทีมงาน <a href=\"https://www.theeraphong.com/\">ธีรพงษ์ เซอร์วิส</a>&nbsp;ได้ดำเนินการกดเสาเข็ม กำแพง กัน ดิน ทั้งในส่วนของกำแพง และสเตย์ เป็นอันเสร็จเรียบร้อย รวมเป็นจำนวนทั้งสิ้น 110 ต้น</p>\r\n\r\n<p><img alt=\"แม็คโคร กดเข็ม\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/180921/180921-4.webp\" style=\"height:375px; width:500px\" /></p>\r\n\r\n<p>รูป แม็คโคร กดเข็ม</p>\r\n\r\n<p>ทั้งนี้ การดำเนินการอาจมีความล่าช้าไปบ้างเล็กน้อยจากการคาดการณ์ไว้ เนื่องจากประสบกับปัญหาเศษหินที่อยู่ใต้น้ำ และสภาพอากาศที่ไม่สามารถควบคุมได้</p>\r\n\r\n<p><img alt=\"เศษหินใต้ดิน\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/180921/180921-1.webp\" style=\"height:500px; width:375px\" /></p>\r\n\r\n<p>รูป หินที่เป็นอุปสรรคหลักสำหรับงานกำแพง กัน ดิน</p>\r\n\r\n<p>แต่ในภาพรวม ก็ยังสามารถดำเนินการไปได้ด้วยดี ทั้งนี้ต้องรอระยะเวลาอีกประมาณ 3 วันเพื่อให้เสาเข็มยึดกับดินได้ดียิ่งขึ้น และจะได้ทำการติดตั้งแผ่นกำแพงกันดินอีกครั้ง ทั้งนี้เสาเข็มไอ 22 ความยาว 10 เมตร ได้ถูกกดลงไปใต้พื้นดินมากกว่ากว่า 8 เมตร ซึ่งสามารถมั่นใจได้ว่า กำแพง กัน ดิน ที่ทางทีมงานเราสร้าง มีความคงทน และแข็งแรงอย่างแน่นอน</p>\r\n\r\n<p><img alt=\"แม็คโครขนย้ายเสาเข็มไอ 22\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/180921/180921-2.webp\" style=\"height:375px; width:500px\" /></p>\r\n\r\n<p>รูป แม็คโครกำลังดำเนินการย้ายเสาเข็มสู่ตำแหน่งที่กำหนด</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>ซึ่งหลังจากนี้ประมาณ 3 วัน ทีมงานจะทำการเสียบแผ่นกำแพงกันดิน แล้วทางทีมงานจะได้ทำการอัพเดทให้ได้ชมในเวลาต่อไป</p>\r\n\r\n<p>อัพเดทงาน ครั้งก่อนหน้า <a href=\"https://www.theeraphong.com/blog/20\">คลิ๊กที่นี่</a></p>\r\n\r\n<p>งานอื่น ๆ <a href=\"https://www.theeraphong.com/\">คลิ๊กที่นี่</a></p>\r\n\r\n<p>&nbsp;</p>', 'images/blogs/1711438109246937.webp', 10, 'เขื่อนกันดิน-ไทรม้า19-EP5', '2021-09-20 16:12:41', '2021-09-20 16:16:08'),
(23, 'สำรวจกำแพง กั้น ดิน พัง สุพรรณบุรี', 'ลงพื้นหน้าดูหน้างาน สำรวจกำแพง กั้น ดินพัง', '<h1>กำแพง กั้น ดิน พังพื้นที่ จ.สุพรรณบุรี</h1>\r\n\r\n<p>วันนี้ทางทีมงาน ธีรพงษ์ ได้รับความไว้วางใจ มีโอกาสได้เข้าดูหน้างาน กำแพง กั้น ดิน พังทลายลง ในพื้นที่จังหวัดสุพรรณบุรี ซึ่งได้สร้างความเสียหายแก่ตัวพื้นที่เป็นอย่างมาก</p>\r\n\r\n<p><img alt=\"กำแพง กั้น ดิน พัง\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/220921/suphan-220921-1.webp\" style=\"height:375px; width:500px\" /></p>\r\n\r\n<p>ซึ่งพื้นที่ ติดริมแม่น้ำ ท่าจีน กำแพงกันดิน เดิม ได้พังยาวตลอดแนว สร้างความเสียหาย โดยเฉพาะ บ้านต้นไม้ ซึ่งที่น่าเสียดายเป็นอย่างมาก&nbsp;</p>\r\n\r\n<p><img alt=\"บ้าน ต้นไม้ พัง\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/220921/suphan-220921-2.webp\" style=\"height:375px; width:500px\" /></p>\r\n\r\n<p>หลังจากลงพื้นที่เพื่อสำรวจความเสียเสร็จเรียบร้อย ทางทีมงานธีรพงษ์ ก็จะได้นำเสนอวิธีการแก้ไขปัญหาระยะยาว ให้คุณลูกค้าเจ้าของพื้นที่เป็น ลำดับถัดไป&nbsp;</p>\r\n\r\n<p>รวมข่าวสาร และบทความ <a href=\"https://www.theeraphong.com/blog\">คลิ๊กที่นี่</a></p>', 'images/blogs/1711592918414737.webp', 10, 'สำรวจกำแพงกั้นดินพัง-สุพรรณบุรี', '2021-09-22 09:15:43', '2021-09-22 09:16:46'),
(24, 'เขื่อนกันดินไทรม้า 19 EP.6', 'ความคืบหน้างานเขือนกันดิน ซอยไทรม้า 19', '<p>อัพเดท ณ วันที่ 27 กันยายน 2564</p>\r\n\r\n<p>ทีมงาน ธีรพงษ์ เซอร์วิส (<a href=\"http://theeraphong.com\">www.theeraphong.com</a>) ได้ดำเนินการกดแผ่นเสียบ สำหรับกำแพงกันดิน เสร็จเรียบร้อย โดยทำการกดลคกลงพื้นดินไป 1.50 เมตร</p>\r\n\r\n<p><img alt=\"\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/270921/saima-1.webp\" style=\"height:500px; width:375px\" /></p>\r\n\r\n<p>ซึ่งตำแหน่งนี้มีความแข็งแรงเพียงพอที่จะรับน้ำหนักจากดินด้านข้างได้อย่างแน่อนนอน เพราะฉะนั้นจึงสามารถเชื่อมั่นได้ว่ากำแพง กัน ดิน ที่ทางธีรพงษ์ เซอร์วิส สร้างขึ้น มีความแข็งแกร่ง และแข็งแรงตามมาตรฐาน</p>\r\n\r\n<p><img alt=\"\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/270921/saima-1.webp\" style=\"height:500px; width:375px\" /></p>\r\n\r\n<p>ส่วนในขึ้นตอนถัดไป ทางทีมงานจะเริ่มทำการเทคาน ทั้งคานด้านบนกำแพง และคานเสตย์ที่จะใช้ยึดเพื่อความแข็งแกร่งให้กำแพงเป็นลำดับถัดไป</p>\r\n\r\n<p>งานก่อนหน้า <a href=\"https://www.theeraphong.com/blog/22\">คลิ๊กที่นี่</a></p>\r\n\r\n<p>รายละเอียดงานกำแพงกันดิน <a href=\"https://www.theeraphong.com/retaining-wall\">คลิ๊กที่นี่&nbsp;</a></p>', 'images/blogs/1712044835626349.webp', 10, 'เขื่อนกันดิน-ไทรม้า19-EP6', '2021-09-27 08:59:48', '2021-09-27 08:59:48'),
(25, 'กำแพง กัน ดิน ซอยบางกร่าง45/5 EP.2', 'อัพเดทงาน กำแพง กัน ดิน ในซอยบางกร่าง 45', '<p>หลังจากเข้าสำรวจหน้างาน และยกกำแพง กัน ดิน เดิมที่พังลงไปในน้ำแล้ว <a href=\"https://www.theeraphong.com/blog/21\">ก่อนหน้านี้</a>&nbsp;การแก้ไขปัญหาระยะยาวต่อมาคือ ทีมงาน จะทำการเข็ม กำแพง กัน ดิน ด้านหน้าของเดิม เพื่อช่วยให้ลูกค้าของเรา ประหยัดค่าใช้จ่าย ไม่ต้องรื้อของเก่าออก ซึ่งจะกำแพง กัน ดิน เดิม จะไม่มีผล ต่อความแข็งแรงของ กำแพง กัน ดินใหม่ที่เราจะสร้างขึ้น</p>\r\n\r\n<p><img alt=\"กำแพง กัน ดิน บางกร่าง \" src=\"https://www.theeraphong.com/image/blogs/blogscontent/270921/bangkrang-2.webp\" style=\"height:500px; width:375px\" /></p>\r\n\r\n<p>ต้องบอกก่อนว่า รอบ ๆ บริเวณหน้างาน บรรยากาศค่อนข้างดีมาก ถือเป็นสิ่งที่ดี ลดความเหนื่อยล้า ของทีมงานทำ กำแพง กัน ดิน ได้มากพอสมควร&nbsp;</p>\r\n\r\n<p><img alt=\"บรรยากาศทำเขื่อนกันดิน\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/270921/bangkrang-1.webp\" style=\"height:500px; width:375px\" /></p>\r\n\r\n<p>ซึ่งวันนี้ หลังจากที่ทีมงาน ธีรพงษ์ เซอร์วิส ได้กดเข็มเสร็จเรียบร้อยแล้ว ขั้นตอนต่อไป ก็จะทำการกด สเตย์ และทำคาน ในลำดับถัดไป</p>\r\n\r\n<p>งานก่อนหน้า <a href=\"https://www.theeraphong.com/blog/21\">คลิ๊กที่นี่</a>&nbsp;</p>\r\n\r\n<p>งานกำแพงกันดินทั้งหมด <a href=\"https://www.theeraphong.com/retaining-wall\">คลิ๊กที่นี่</a></p>', 'images/blogs/1712045863923793.webp', 10, 'กำแพงกันดิน-ซอยบางกร่าง45-5-EP2', '2021-09-27 09:16:08', '2021-09-28 07:18:11'),
(26, 'ขุดบ่อน้ำ ปากน้ำกระโจมทอง', 'งานขุดบ่อน้ำ สถานที่ ที่ปากน้ำกระโจมทอง', '<p>งาน&nbsp;ขุด บ่อน้ำ สามารถเรียกใช้บริการกับ ทางธีรพงษ์ เซอร์วิส ได้</p>\r\n\r\n<p><img alt=\"ขุด บ่อน้ำ\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/270921/garden-1.webp\" style=\"height:375px; width:500px\" /></p>\r\n\r\n<p>โดยได้รับมอบให้ขุดบ่อ จากพื้นที่วางเปล่า โดยขนาดที่ขุด คือ กว้าง 7 เมตร ยาว 20 เมตร ลึก 2.50 เมตร</p>\r\n\r\n<p><img alt=\"ที่ดินเปล่า\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/270921/garden-2.webp\" style=\"height:375px; width:500px\" /></p>\r\n\r\n<p>ขอขอบพระคุณที่ไว้วางในใน ทีมงาน ธีรพงษ์ เซอร์วิส ครับ</p>\r\n\r\n<p>งานขุด บ่อ ดิน และงานสวนอื่น <a href=\"https://www.theeraphong.com/garden-plot\">คลิ๊กที่นี่</a></p>', 'images/blogs/1712046972067174.webp', 11, 'ขุดบ่อน้ำ-ปากน้ำกระโจมทอง', '2021-09-27 09:33:45', '2021-09-27 09:33:45'),
(27, 'กำแพง กันดิน ซอยไทรม้า 19', 'ส่งงานก่อสร้างกำแพง กันดินซอยไทรม้ 19', '<h1><strong>กำแพง กันดิน เสริมด้วยสเตย์</strong></h1>\r\n\r\n<blockquote>\r\n<p>กำแพง กันดิน สเตย์ ราคาเท่าไหร่?</p>\r\n\r\n<p>กำแพงกันดินสเตย์มีวิธีการสร้างยังไง?</p>\r\n</blockquote>\r\n\r\n<p>วันนี้ทีมงาน ธีรพงษ์ เซอร์วิส ได้สร้างกำแพง กันดินสเตย์ เสร็จเรียบร้อย ซึ่งจะทางทีมงานจะมานำเสนอ หรือเล่าให้ฟังถึงวิธีการสร้างเขื่อนกันดินแบบสเตย์ ว่ามีวิธีการทำงาน หรือการก่อสร้างที่นิยมกัน มันเป็นแบบใด</p>\r\n\r\n<p><img alt=\"กำแพงกันดินมุมสูง-1\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/271021/271021-4.webp\" style=\"height:373px; width:500px\" /></p>\r\n\r\n<p>รูปมุมสูงกำแพง กันดิน</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>ก่อนอื่นเลยทำไมราคาของกำแพงกันดินถึงมีลักษณะที่แตกต่างกัน</p>\r\n\r\n<p>สิ่งที่ผู้รับเหมาจะประเมินราคาของกำแพงกันดินนั้น มักจะดูจากลักษณะของพื้นที่บริเวรณนั้นเป็นหลัก คือลักษณะของดิน ลักษณะทางเข้าของพื้นที่ ซึ่งจำเป็นต้องมีการนำเครื่องจักรเข้าพื้นที่ ลักษณะของดินใต้พื้นน้ำ เป็นต้น ซึ่งงานกำแพงกันดิน ที่ซอยไทรม้านี้ สิ่งที่เป็นอุปสรรค ในการทำงานอย่างยิ่งคือ&nbsp;</p>\r\n\r\n<p>1. หินที่อยู่บริเวณใต้น้ำทำให้การกดเข็มไอ หรือเข็มไมโครไพล์เป็นไปด้วยความยากลำบากต้องใช้รถแบคโฮเคลียหินในบริเวณนั้นทุกต้น ก่อนการกดเสาเข็ม ซึ่งทำให้การดำเนินการค่อนข้างไปด้วยความล่าช้า</p>\r\n\r\n<p><img alt=\"เศษหินใต้น้ำ\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/180921/180921-1.webp\" style=\"height:500px; width:375px\" /></p>\r\n\r\n<p>รูป เศษหินใต้น้ำ</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>2. ดินบริเวณหน้างานมีลักษณะถูกถมมาไม่ได้ กล่าวคือ ไม่มีการบดอัดก่อน ซึ่งทำให้รถแบคโฮไม่สามารถเข้าพื้นที่ได้โดยตรง ต้องมีการปูแผ่นเหล็กรองล้อรถแบคโฮก่อน ซึ่งรายละเอียดของการถมดิน สามารถคลิ๊กได้&nbsp;<a href=\"https://www.theeraphong.com/landfill\">ที่นี่</a></p>\r\n\r\n<p><img alt=\"แบคโฮ\" src=\"https://www.theeraphong.com/image/blogs/1711139361714176.webp\" style=\"height:480px; width:600px\" /></p>\r\n\r\n<p>รูป แบคโฮเดินบนแผ่นเหล็ก</p>\r\n\r\n<p>3. และลำดับสุดท้าย ซึ่งเป็นสิ่งที่ไม่สามารถคาดการณ์ได้ คือพายุ ลม ฝน ซึ่งจะทำให้การดำเนินการมีการหยุดชะงักลง</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"แบบกำแพงกันดิน\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/271021/271021-1.webp\" style=\"height:310px; width:500px\" /></p>\r\n\r\n<p>รูป แบบกำแพง กันดิน</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>ส่วนวิธีการสร้างกำแพง กันดิน คือ</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>1. ดำเนินการกดเสาเข็มลงพื้น เพื่อวางแผ่นเสียบสำหรับรองรับดินที่มาจากด้านข้างซึ่งจะเป็นเข็มหลักที่คอยรองรับแรง โดยเข็มที่เราใช้ในงานนี้จะเป็นเข็มไมโครไพล์ แบบไอขนาด 18 เซนติเมตร ยาว 10 เมตร ซึ่งเสาเข็มนี้จะถูกกดลงจากพื้นประมาณ 8-9 เมตร</p>\r\n\r\n<p><img alt=\"กำแพงกันดิน ด้านหน้า\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/271021/271021-7.webp\" style=\"height:373px; width:500px\" /></p>\r\n\r\n<p>รูป ด้านหน้ากำแพงกันดิน</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>2. ดำเนินการกดเข็มสเตย์ เพื่อใช้เป็นที่สำหรับยึดตัวกำพงกันดินไว้ เพิ่มความแข็งแรงของตัวกำแพงกันดิน ถ้ากำแพงกันดินใด ไม่มีสเตย์ ก็มักจะทำให้ตัวกำแพงล้ม โดยใช้เข็มไมโครไพล์ แบบไอขนาด 18 เซนติเมตร ยาว 10 เมตร เช่นกัน และจะกดลงจากพื้นประมาณ 9 เมตร และห่างจากเสาเข็มหลักของตัวกำแพงประมาณ 1.50 เมตร</p>\r\n\r\n<p><img alt=\"แนวสเตย์\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/271021/271021-3.webp\" style=\"height:373px; width:500px\" /></p>\r\n\r\n<p>รูป แนวสเตย์</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>สเตย์คือ การหล่อคอนกรีตเสริมเหล็กยึดระหว่างเข็มของตัวเขื่อน กับเข็มสเตย์</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<ol>\r\n	<li>เสียบแผ่นพื้น&nbsp;</li>\r\n	<li>เทคานด้านบน และเทคานสเตย์ เข้าด้วยกัน</li>\r\n</ol>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>ซึ่งก่อนที่จะดำเนินการเทคานด้านบน ทางลูกค้าของเราคือคุณบ๊อบบี้ เราได้รับความไว้วางใจจากคุณบ๊อบบี้ ให้ดำเนินการก่อสร้างรั้วบนตัวสันกำแพงกันดินอีก 3 แบบ คือ</p>\r\n\r\n<ol>\r\n	<li>กำแพงแบบทึบ เพื่อเพิ่มความเป็นส่วนตัวให้กับเจ้าของพื้นที่</li>\r\n	<li>กำแพงเหล็ก เพื่อเพิ่มความสวยงามให้กับตัวรัว</li>\r\n	<li>กำแพงแบบเตี้ย เพิ่มจะได้ไม่บดบังทัศนียภาพบริเวณที่ติดริมน้ำ</li>\r\n</ol>\r\n\r\n<p><img alt=\"กำแพงทึบ\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/271021/271021-6.webp\" style=\"height:667px; width:500px\" /></p>\r\n\r\n<p>รูป กำแพงทึบหลังเขื่อนกันดิน</p>\r\n\r\n<p>ถ้าเห็นจากขนาดของสเตย์ และความลึกของเสาเข็มที่ได้กดลงไป จึงสามารถมั่นใจได้ว่า ตัวกำแพงอยู่ได้ยาวนาน เป็นหลายสิบ หลายร้อยปี แน่นอน</p>\r\n\r\n<p>ซึ่งถ้าท่านใดสนใจ หรือว่าอยากหาที่ปรึกษาเรื่องการทำกำแพงกันดิน สามารถโทรปรึกษาได้ฟรี ที่&nbsp;062-718-8847</p>\r\n\r\n<p>หรือรายละเอียดอื่น ๆ เกี่ยวกับกำแพงกันดิน คลิ๊ก&nbsp;<a href=\"https://www.theeraphong.com/retaining-wall\">ที่นี่</a></p>\r\n\r\n<p>&nbsp;</p>', 'images/blogs/1714793341402425.webp', 10, 'กำแพงกันดิน-ซอยไทรม้า19-ส่งงาน', '2021-10-27 17:06:07', '2021-10-27 17:13:27'),
(28, 'เทพื้นปูน ราคาต่อ ตาราง เมตร 2567 | รับเหมาเทพื้นคอนกรีต มืออาชีพ', 'เช็คราคาการเทพื้นปูนล่าสุดปี 2567 พร้อมข้อมูลเทพื้นคอนกรีต พื้นปูนขัดมัน ราคาค่าแรง ตารางเมตรละเท่าไหร่ บริการเทพื้นคุณภาพ ติดต่อทีมงานมืออาชีพได้ที่นี่', '<h2>💰 ราคาการเทพื้นปูนต่อ ตารางเมตร ปี 2567</h2><p>ราคาการเทพื้นปูนในปี 2567 มีความหลากหลายขึ้นอยู่กับความหนาของพื้นและประเภทของคอนกรีตที่ใช้ โดยทั่วไป ราคาจะอยู่ในช่วงดังนี้:</p><h3>🔹 ความหนา 10 ซม.</h3><ul><li><p>คอนกรีต 180 ksc: ประมาณ 390–420 บาท/ตร.ม.</p></li><li><p>คอนกรีต 210 ksc: ประมาณ 410–430 บาท/ตร.ม.</p></li><li><p>คอนกรีต 240 ksc: ประมาณ 440–460 บาท/ตร.ม.</p></li></ul><h3>🔹 ความหนา 15 ซม.</h3><ul><li><p>คอนกรีต 180 ksc: ประมาณ 490–520 บาท/ตร.ม.</p></li><li><p>คอนกรีต 210 ksc: ประมาณ 510–530 บาท/ตร.ม.</p></li><li><p>คอนกรีต 240 ksc: ประมาณ 540–560 บาท/ตร.ม.</p></li></ul><h3>🔹 ความหนา 20 ซม.</h3><ul><li><p>คอนกรีต 180 ksc: ประมาณ 790–820 บาท/ตร.ม.</p></li><li><p>คอนกรีต 210 ksc: ประมาณ 850–860 บาท/ตร.ม.</p></li></ul><p>คอนกรีต 240 ksc: ประมาณ 890–900 บาท/ตร.ม.</p><p>ราคาดังกล่าวเป็นราคาประมาณการและอาจเปลี่ยนแปลงได้ตามปัจจัยต่าง ๆ เช่น พื้นที่ที่ต้องการเทพื้น ความยากง่ายของงาน และต้นทุนวัสดุในแต่ละพื้นที่</p><hr><h2>🏡 ประเภทของพื้นปูนและการใช้งาน</h2><h3>✅ พื้นปูนขัดมัน</h3><p>พื้นปูนขัดมันเป็นที่นิยมในงานตกแต่งภายในและภายนอก เนื่องจากมีความเรียบเนียนและดูทันสมัย ราคาการเทพื้นปูนขัดมันอยู่ที่ประมาณ 450–500 บาท/ตร.ม. </p><img src=\"https://minio.speedynetloans.net/theeraphong/images/services/51ed6b20-f477-458d-a61d-411010457881.webp\"><h3>✅ <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"https://www.theeraphong.com/pour-concrete\">พื้นคอนกรีตเสริมเหล็ก</a></h3><p>เหมาะสำหรับพื้นที่ที่ต้องรับน้ำหนักมาก เช่น โรงงานหรือโรงจอดรถ ราคาจะสูงขึ้นตามความหนาและประเภทของเหล็กที่ใช้เสริม</p><hr><h2>📌 ปัจจัยที่มีผลต่อราคาการเทพื้นปูน</h2><ol><li><p><strong>ความหนาของพื้น</strong>: ยิ่งพื้นหนา ราคาจะยิ่งสูงขึ้นเนื่องจากต้องใช้วัสดุมากขึ้น</p></li><li><p><strong>ประเภทของคอนกรีต</strong>: คอนกรีตที่มีความแข็งแรงสูงจะมีราคาสูงกว่า</p></li><li><p><strong>พื้นที่ที่ต้องการเทพื้น</strong>: พื้นที่ขนาดใหญ่สามารถต่อรองราคาได้มากกว่าพื้นที่ขนาดเล็ก</p></li><li><p><strong>ความยากง่ายของงาน</strong>: พื้นที่ที่เข้าถึงยากหรือมีรูปทรงซับซ้อนจะมีค่าแรงสูงขึ้น</p></li></ol><hr><h2>📞 ติดต่อบริการเทพื้นปูนมืออาชีพ</h2><p>หากคุณกำลังมองหาผู้รับเหมาเทพื้นปูนที่มีประสบการณ์และเชื่อถือได้ สามารถติดต่อเราได้ที่:</p><ul><li><p><strong>โทรศัพท์</strong>: <strong>062-718-8847</strong></p></li><li><p><strong>LINE ID</strong>: <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"https://line.me/ti/p/h9SHumuTEB\"><strong>0627188847</strong></a></p></li><li><p><strong>อีเมล</strong>: <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"mailto:theeraphong.services@gmail.com\"><strong>theeraphong.services@gmail.com</strong></a></p></li></ul><p>เรามีทีมงานมืออาชีพพร้อมให้บริการคุณในทุกขั้นตอนของการเทพื้นปูน ตั้งแต่การวางแผนจนถึงการส่งมอบงาน</p><hr><h2>📝 สรุป</h2><p>การเทพื้นปูนเป็นงานที่ต้องการความชำนาญและการวางแผนที่ดี เพื่อให้ได้พื้นผิวที่มีคุณภาพและทนทานต่อการใช้งาน การเลือกใช้บริการจากผู้รับเหมาที่มีประสบการณ์จะช่วยให้คุณมั่นใจในคุณภาพของงานและความคุ้มค่าของงบประมาณ</p><p>หากคุณต้องการข้อมูลเพิ่มเติมหรือคำปรึกษาเกี่ยวกับการเทพื้นปูน สามารถติดต่อเราได้ตามข้อมูลที่ระบุไว้ข้างต้น เรายินดีให้บริการคุณด้วยความมืออาชีพและใส่ใจในทุกรายละเอียดของงาน</p>', 'images/services/6e825854-deb8-43c4-a02a-24e2dc9dab1f.webp', 27, 'เทพื้นปูน-ราคาต่อตารางเมตร-2567-รับเหมาเทพื้นคอนกรีต-มืออาชีพ', '2025-05-18 15:55:34', '2025-05-18 15:55:34'),
(29, 'เทปูน 1 คิว ใช้ปูนกี่ถุง? คำนวณวัสดุและต้นทุนอย่างมืออาชีพ', 'เรียนรู้วิธีคำนวณปริมาณปูน ทราย หิน สำหรับเทคอนกรีต 1 คิว พร้อมข้อมูลราคาปูนและพื้นที่ที่สามารถเทได้จากปูน 1 ถุง เพื่อวางแผนงานก่อสร้างอย่างมืออาชีพ', '<h1>📌 คอนกรีต 1 คิว ใช้ปูนกี่ถุง?</h1><img src=\"https://minio.speedynetloans.net/theeraphong/images/services/2fdd5a76-d18b-44de-b845-cb99e4a80b82.webp\"><p>สำหรับคอนกรีตที่ใช้ในงานโครงสร้างทั่วไป (กำลังอัด 280 กก./ตร.ซม.) ส่วนผสมที่แนะนำมีดังนี้:</p><ul><li><p><strong>ปูนซีเมนต์ปอร์ตแลนด์</strong>: 325 กิโลกรัม (ประมาณ 6.5 ถุง)</p></li><li><p><strong>ทรายหยาบ</strong>: 820 กิโลกรัม</p></li><li><p><strong>หินขนาด 20 มม.</strong>: 1,120 กิโลกรัม</p></li><li><p><strong>น้ำ</strong>: 130 ลิตร</p></li></ul><hr><h2>🧱 ปูน 1 ถุง ใช้ได้กี่ตารางเมตร?</h2><p>ปูนซีเมนต์ 1 ถุง (50 กก.) เมื่อผสมเป็นคอนกรีต สามารถเทพื้นหนา 5 ซม. ได้พื้นที่ประมาณ 0.87 ตารางเมตร</p><img src=\"https://minio.speedynetloans.net/theeraphong/images/services/f05b7829-3b67-4941-955e-1d9e19b82527.webp\"><hr><h2>🧮 คำนวณปริมาณวัสดุสำหรับคอนกรีต 1 คิว</h2><p>การผสมคอนกรีต 1 คิว ด้วยสัดส่วน 1:2:4 (ปูน:ทราย:หิน) จะใช้วัสดุดังนี้:</p><ul><li><p><strong>ปูนซีเมนต์</strong>: ประมาณ 6.5 ถุง (325 กก.)</p></li><li><p><strong>ทรายหยาบ</strong>: ประมาณ 0.57 คิว (820 กก.)</p></li><li><p><strong>หินขนาด 20 มม.</strong>: ประมาณ 1.09 คิว (1,120 กก.)</p></li></ul><hr><h2>💰 ปูน 1 ถุง ราคาเท่าไหร่?</h2><p>ราคาปูนซีเมนต์ปอร์ตแลนด์ขนาด 50 กก. อยู่ระหว่าง 145 – 177 บาทต่อถุง ขึ้นอยู่กับยี่ห้อและประเภทของปูน</p><hr><h2>📏 คอนกรีต 1 คิว เทได้กี่ตารางเมตร?</h2><p>การเทคอนกรีต 1 คิว สามารถครอบคลุมพื้นที่ได้ดังนี้</p><ul><li><p><strong>ความหนา 10 ซม.</strong>: 10 ตารางเมตร</p></li><li><p><strong>ความหนา 15 ซม.</strong>: 6.67 ตารางเมตร</p></li></ul><h2><strong>ความหนา 20 ซม.</strong>: 5 ตารางเมตร<br><br>📌 สรุป</h2><ul><li><p>การคำนวณปริมาณวัสดุที่ต้องใช้ในการเทคอนกรีตเป็นสิ่งสำคัญเพื่อควบคุมงบประมาณและคุณภาพของงานก่อสร้าง หากคุณต้องการความช่วยเหลือในการวางแผนหรือสั่งซื้อวัสดุก่อสร้าง สามารถติดต่อทีมงานของเราได้ที่ <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"https://www.theeraphong.com/pour-concrete\">บริษัทธีรพงษ์เซอร์วิส</a> เพื่อรับคำปรึกษาและบริการที่มีคุณภาพ</p></li></ul>', 'images/services/cd2ec5b2-096b-46cd-bf8b-82a3bf655aed.webp', 27, 'เทปูน-1-คิว-ใช้ปูนกี่ถุง-คำนวณวัสดุและต้นทุนอย่างมืออาชีพ', '2025-05-23 09:15:37', '2025-05-29 14:23:26'),
(30, 'ถมที่ด้วยเศษวัสดุก่อสร้าง ช่วยประหยัด เสริมพื้นแข็งแรง เหมาะกับงานสร้างกำแพงกันดิน', 'รู้จักการถมที่ด้วยเศษวัสดุก่อสร้าง พร้อมแนวทางเลือกใช้วัสดุให้ปลอดภัย ประหยัด และเตรียมพื้นที่สำหรับงานก่อสร้างกำแพงกันดินอย่างมีประสิทธิภาพ พร้อมบริการจากมืออาชีพ', '<h2>ถมที่ด้วยเศษวัสดุก่อสร้าง ทางเลือกประหยัด เตรียมพื้นที่ก่อนสร้างกำแพงกันดิน</h2><img src=\"https://minio.speedynetloans.net/theeraphong/images/services/0dcca921-8ae9-4259-8708-178f97ecc4e7.webp\"><p>ในงานก่อสร้าง \"กำแพงกันดิน\" โดยเฉพาะในโครงการขนาดกลางถึงใหญ่ หนึ่งในขั้นตอนสำคัญที่หลายคนอาจมองข้ามคือ <strong>การถมพื้นที่หน้างาน</strong> เพื่อให้เครื่องจักรสามารถเข้าไปดำเนินการได้สะดวก และเป็นการเตรียมฐานรากให้แข็งแรงก่อนจะเริ่มเจาะหรือตอกเสาเข็ม</p><p>หลายโครงการเลือก <strong>“ถมที่ด้วยเศษวัสดุก่อสร้าง”</strong> ซึ่งเป็นอีกหนึ่งทางเลือกที่ทั้งคุ้มค่าและเป็นมิตรกับสิ่งแวดล้อม หากเลือกใช้อย่างถูกวิธี</p><h2>ทำไมต้องถมที่ก่อนสร้าง<a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"https://www.theeraphong.com/retaining-wall\">กำแพงกันดิน</a>?</h2><img src=\"https://minio.speedynetloans.net/theeraphong/images/services/57de4d73-ab3a-4871-9504-4e99b56798f1.webp\"><ul><li><p>เพิ่มความแข็งแรงให้พื้นผิว</p></li><li><p>ช่วยลดระดับความสูง-ต่ำของพื้นที่</p></li><li><p>เพิ่มความสะดวกให้กับเครื่องจักรและทีมช่าง</p></li><li><p>ป้องกันน้ำขังหรือลื่นในช่วงฝนตก</p></li></ul><h2>เศษวัสดุก่อสร้างคืออะไร? มีอะไรบ้าง?</h2><img src=\"https://minio.speedynetloans.net/theeraphong/images/services/1b07cce0-4bea-4127-b399-6bd8d9fbd6c9.webp\"><p><strong>เศษวัสดุก่อสร้าง (Construction Waste)</strong> คือวัสดุเหลือใช้จากไซต์งาน เช่น</p><ul><li><p>เศษปูน / ปูนติดกระเบื้อง / ปูนแห้ง</p></li><li><p>อิฐหัก / คอนกรีตแตก</p></li><li><p>กระเบื้องที่แตกหัก</p></li><li><p>เหล็กดัด / เศษเหล็ก</p></li><li><p>ทราย / เศษไม้จากแบบหล่อ</p></li><li><p>เศษวัสดุธรรมชาติ เช่น เศษดิน หิน กรวด</p></li></ul><blockquote><p>เ<em>ศษวัสดุเหลือใช้มีอะไรบ้าง, เศษวัสดุธรรมชาติ, เศษวัสดุมีอะไรบ้าง</em></p></blockquote><hr><h2>ข้อดีของการถมที่ด้วยเศษวัสดุก่อสร้าง</h2><img src=\"https://minio.speedynetloans.net/theeraphong/images/services/72dcb8ff-71b2-414a-a564-7650a3e44778.webp\"><ul><li><p>✅ <strong>ประหยัดงบ</strong>: ราคาถูกกว่าทรายหรือดินล้วน</p></li><li><p>✅ <strong>ใช้วัสดุหมุนเวียน (Recycle)</strong>: ลดขยะในไซต์งาน</p></li><li><p>✅ <strong>แข็งแรง เหมาะกับเครื่องจักรหนัก</strong></p></li><li><p>✅ <strong>ลดเวลาการเตรียมหน้างาน</strong></p></li></ul><hr><h2>แล้ว “เศษปูน” ใช้ถมที่ได้ไหม?</h2><p>แน่นอนว่าใช้ได้ โดยเฉพาะในกรณีที่คุณกำลังจะเตรียมพื้นที่ให้ “เครื่องจักร” เช่น แบคโฮ รถตอกเสาเข็ม เข้ามาทำงาน</p><h3>💡 <strong>ข้อควรรู้เกี่ยวกับเศษปูน</strong></h3><ul><li><p>ต้องไม่มีสารเคมีปนเปื้อน</p></li><li><p>ไม่ควรมีเหล็กเส้นยาว ๆ (อาจเป็นอันตราย)</p></li><li><p>ถ้าเป็นเศษปูนที่ติดกระเบื้อง ควรแยกก่อน</p></li></ul><blockquote><p><em>เศษปูนถมที่, เศษปูนทิ้งที่ไหน, เศษปูนทำอะไรได้บ้าง</em></p></blockquote><hr><h2>ถมที่ด้วยเศษวัสดุก่อสร้าง ต้องดูอะไรบ้าง?</h2><ol><li><p><strong>ตรวจสอบชนิดของวัสดุ</strong> – ต้องมั่นใจว่าไม่มีของมีคม หรือวัสดุอันตราย</p></li><li><p><strong>เลือกทีมงานที่เชี่ยวชาญ</strong> – เพื่อควบคุมระดับความแน่นของชั้นถม</p></li><li><p><strong>วางแผนระบายน้ำ</strong> – ป้องกันการเซาะพัง</p></li><li><p><strong>ใช้เครื่องอัดแน่น</strong> – ให้พื้นไม่ทรุดในอนาคต</p></li></ol><hr><h2>ราคาในการถมที่ด้วยเศษวัสดุก่อสร้าง</h2><p>ประเภทวัสดุราคาโดยประมาณ (บาท/คิว)เศษปูน / คอนกรีตเก่า100 – 200 บาทอิฐหัก / เศษกระเบื้อง80 – 150 บาทเศษวัสดุผสมดิน / หิน50 – 120 บาท</p><blockquote><p>💡 ราคาขึ้นอยู่กับระยะทางขนส่งและปริมาณ</p></blockquote><blockquote><p><em>เศษปูนราคา, เศษปูนถมที่ราคา, ถมดินเศษปูน</em></p></blockquote><hr><h2>แล้วเศษวัสดุเหล่านี้… ทิ้งที่ไหน?</h2><img src=\"https://minio.speedynetloans.net/theeraphong/images/services/2d1b89ab-fa0a-4c2a-a9e2-b2fd383da8c9.webp\"><p>เศษวัสดุก่อสร้างไม่ควรทิ้งมั่วซั่ว เพราะอาจผิดกฎหมายและสร้างมลพิษ<br>คุณสามารถเลือกวิธีจัดการได้ เช่น:</p><ul><li><p>ส่งไปยัง <strong>ศูนย์กำจัดขยะก่อสร้าง</strong></p></li><li><p>ส่งเข้าโรงงานรีไซเคิล</p></li><li><p>หาผู้รับเหมาที่สามารถนำไปใช้ในการถมที่ได้</p></li></ul><blockquote><p>เ<em>ศษวัสดุก่อสร้างทิ้งที่ไหน, เศษปูนทิ้งที่ไหน</em></p></blockquote><hr><h2>ตัวอย่างผลงาน: งานถมพื้นที่เพื่อสร้างกำแพงกันดิน @นนทบุรี</h2><img src=\"https://minio.speedynetloans.net/theeraphong/images/services/966a0419-99ac-4e8c-b6f9-d9bfaa8af967.webp\"><p>เราเพิ่งดำเนินการโครงการถมพื้นที่ด้วยเศษปูนบดละเอียด ร่วมกับเศษอิฐ-หิน บนพื้นที่กว่า 500 ตร.ม.<br>จุดประสงค์คือเพื่อให้เครื่องจักรเจาะเสาเข็มเข้าทำงานได้อย่างปลอดภัย โดยควบคุมระดับแน่นดินตามมาตรฐานวิศวกรรม</p><p>📌 <strong>ผลลัพธ์</strong>: ไม่มีการทรุดตัว / ทำงานต่อได้ทันทีในวันรุ่งขึ้น</p><hr><h2>ทำไมต้องเลือกเรา?</h2><ul><li><p>✅ ประสบการณ์ด้านงานถมที่-ฐานรากกว่า 20 ปี</p></li><li><p>✅ มีเครื่องมือเฉพาะทาง</p></li><li><p>✅ ทีมงานเข้าใจหน้างานก่อสร้างจริง</p></li><li><p>✅ พร้อมให้คำปรึกษาก่อนเริ่มงาน</p></li></ul><hr><h2>สนใจใช้บริการถมที่ด้วยเศษวัสดุก่อสร้าง?</h2><p>📞 <strong>062-718-8847, 087-700-7463</strong><br>🌐 เยี่ยมชมผลงานและรีวิวเพิ่มเติมได้ที่ <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"/\">www.theeraphong.com</a><br>📍 รองรับพื้นที่กรุงเทพฯ นนทบุรี ปทุมธานี สมุทรปราการ และใกล้เคียง</p>', 'images/services/0dcca921-8ae9-4259-8708-178f97ecc4e7.webp', 10, 'ถมที่ด้วยเศษวัสดุก่อสร้าง-ช่วยประหยัด-เสริมพื้นแข็งแรง-เหมาะกับงานสร้างกำแพงกันดิน', '2025-05-29 15:12:08', '2025-05-29 15:29:00');
